import Layout from '../components/Layout';
import BookSearch from '../components/BookSearch';
import BookList from '../components/BookList';
import { useState } from 'react';

// Placeholder data for UI demo
const demoBooks = [
  { id: 1, title: 'Introduction to Algorithms', author: 'Cormen', category: 'CS', isbn: '9780262033848', aisle: 'A', shelf: '1', quantity: 3 },
  { id: 2, title: 'Modern Physics', author: 'Tipler', category: 'Physics', isbn: '9780716783319', aisle: 'B', shelf: '2', quantity: 0 },
];

export default function Home() {
  const [filters, setFilters] = useState({ title: '', author: '', aisle: '' });
  const [books, setBooks] = useState(demoBooks);

  function handleSearch() {
    setBooks(
      demoBooks.filter(
        b =>
          (!filters.title || b.title.toLowerCase().includes(filters.title.toLowerCase())) &&
          (!filters.author || b.author.toLowerCase().includes(filters.author.toLowerCase())) &&
          (!filters.aisle || b.aisle.toLowerCase() === filters.aisle.toLowerCase())
      )
    );
  }

  // Dashboard summary cards
  const totalBooks = demoBooks.length;
  const availableBooks = demoBooks.filter(b => b.quantity > 0).length;
  const borrowedBooks = demoBooks.filter(b => b.quantity === 0).length;

  return (
    <Layout>
      <div className="mb-10 grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="card flex flex-col items-center">
          <span className="text-4xl font-extrabold text-brand-green mb-1">{totalBooks}</span>
          <span className="text-lg font-semibold text-gray-700">Total Books</span>
        </div>
        <div className="card flex flex-col items-center">
          <span className="text-4xl font-extrabold text-green-700 mb-1">{availableBooks}</span>
          <span className="text-lg font-semibold text-gray-700">Available Books</span>
        </div>
        <div className="card flex flex-col items-center">
          <span className="text-4xl font-extrabold text-red-700 mb-1">{borrowedBooks}</span>
          <span className="text-lg font-semibold text-gray-700">Borrowed Books</span>
        </div>
      </div>
      <div className="mb-10">
        <BookSearch filters={filters} setFilters={setFilters} onSearch={handleSearch} />
      </div>
      <BookList books={books} />
    </Layout>
  );
}
