import React from 'react';

export default function BookSearch({ filters, setFilters, onSearch }) {
  return (
    <form className="card flex flex-col md:flex-row gap-4 items-end mb-6" role="search" aria-label="Book search form" onSubmit={e => { e.preventDefault(); onSearch(); }}>
      <label className="flex-1 w-full" htmlFor="search-title">
        <span className="block text-sm font-medium mb-1">Title</span>
        <input id="search-title" name="title" type="text" className="w-full p-2 border border-brand-border rounded focus:outline-none focus:ring-2 focus:ring-brand-green" value={filters.title} onChange={e => setFilters(f => ({ ...f, title: e.target.value }))} aria-label="Search by title" />
      </label>
      <label className="flex-1 w-full" htmlFor="search-author">
        <span className="block text-sm font-medium mb-1">Author</span>
        <input id="search-author" name="author" type="text" className="w-full p-2 border border-brand-border rounded focus:outline-none focus:ring-2 focus:ring-brand-green" value={filters.author} onChange={e => setFilters(f => ({ ...f, author: e.target.value }))} aria-label="Search by author" />
      </label>
      <label className="flex-1 w-full" htmlFor="search-aisle">
        <span className="block text-sm font-medium mb-1">Aisle</span>
        <input id="search-aisle" name="aisle" type="text" className="w-full p-2 border border-brand-border rounded focus:outline-none focus:ring-2 focus:ring-brand-green" value={filters.aisle} onChange={e => setFilters(f => ({ ...f, aisle: e.target.value }))} aria-label="Search by aisle" />
      </label>
      <button type="submit" className="btn-primary min-w-[120px] md:mt-0 mt-4" aria-label="Search books">Search</button>
    </form>
  );
}
