import React from 'react';

export default function BookCard({ book }) {
  return (
    <article className="card mb-6" tabIndex={0} aria-label={`Book: ${book.title}`}>
      <header className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-bold text-brand-green" id={`book-title-${book.id}`}>{book.title}</h2>
        <span
          className={`px-3 py-1 rounded-full text-xs font-semibold shadow-sm ${book.quantity > 0 ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}
          role="status" aria-live="polite"
        >
          {book.quantity > 0 ? 'Available' : 'Unavailable'}
        </span>
      </header>
      <div className="grid gap-1 text-sm text-gray-700">
        <span><strong>Author:</strong> {book.author}</span>
        <span><strong>Category:</strong> {book.category}</span>
        <span><strong>ISBN:</strong> {book.isbn}</span>
        <span><strong>Aisle:</strong> {book.aisle}</span>
        <span><strong>Shelf:</strong> {book.shelf}</span>
        <span><strong>Quantity:</strong> {book.quantity}</span>
      </div>
    </article>
  );
}
